import{_ as a,o as t,c as s,aj as i}from"./chunks/framework.DEEoir6m.js";const u=JSON.parse('{"title":"QGIS Plugin","description":"Install and use the GISPulse QGIS plugin — backend connection, dataset browser, jobs, OGC, MVT.","frontmatter":{"title":"QGIS Plugin","description":"Install and use the GISPulse QGIS plugin — backend connection, dataset browser, jobs, OGC, MVT."},"headers":[],"relativePath":"en/plugins/qgis.md","filePath":"en/plugins/qgis.md"}'),l={name:"en/plugins/qgis.md"};function n(o,e,r,d,h,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="qgis-plugin" tabindex="-1">QGIS Plugin <a class="header-anchor" href="#qgis-plugin" aria-label="Permalink to &quot;QGIS Plugin&quot;">​</a></h1><p>The GISPulse QGIS plugin connects QGIS to a GISPulse backend (local or remote) to browse datasets, execute rules, and load layers via OGC API Features, PostGIS, and MVT.</p><p><strong>Compatibility:</strong> QGIS 3.28 -- 4.x</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="from-the-qgis-plugin-manager" tabindex="-1">From the QGIS Plugin Manager <a class="header-anchor" href="#from-the-qgis-plugin-manager" aria-label="Permalink to &quot;From the QGIS Plugin Manager&quot;">​</a></h3><ol><li>In QGIS: <strong>Plugins -&gt; Manage and Install Plugins</strong></li><li>Search for <strong>GISPulse</strong></li><li>Click <strong>Install</strong></li></ol><h3 id="manual-installation-development" tabindex="-1">Manual installation (development) <a class="header-anchor" href="#manual-installation-development" aria-label="Permalink to &quot;Manual installation (development)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Clone the repository</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/gispulse/gispulse</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gispulse/clients/qgis</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Build the plugin (creates gispulse_qgis.zip)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build_plugin.py</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install in QGIS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gispulse_qgis</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/share/QGIS/QGIS3/profiles/default/python/plugins/</span></span></code></pre></div><p>Enable the plugin in <strong>Plugins -&gt; Manage and Install Plugins -&gt; Installed</strong>.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>On first launch, the connection dialog opens:</p><ol><li><strong>Server URL</strong>: URL of your GISPulse backend (e.g., <code>http://localhost:8001</code> or <code>https://gispulse.example.com</code>)</li><li><strong>API Key</strong>: API key if your server is secured (leave empty for a local server without auth)</li><li>Click <strong>Test Connection</strong> to verify</li><li><strong>OK</strong> to confirm</li></ol><p>Settings are saved in QGIS settings (encrypted if a key is defined).</p><h2 id="available-panels" tabindex="-1">Available Panels <a class="header-anchor" href="#available-panels" aria-label="Permalink to &quot;Available Panels&quot;">​</a></h2><p>The plugin adds four panels accessible via <strong>View -&gt; Panels</strong>:</p><h3 id="datasets-panel" tabindex="-1">Datasets Panel <a class="header-anchor" href="#datasets-panel" aria-label="Permalink to &quot;Datasets Panel&quot;">​</a></h3><ul><li>Lists datasets registered on the GISPulse server</li><li>Upload a spatial file directly from QGIS</li><li>Load a layer with a single click: <ul><li><strong>OGC Features</strong> -- vector layer via the OGC API (automatic pagination)</li><li><strong>MVT</strong> -- vector tiles for large volumes</li><li><strong>PostGIS</strong> -- direct connection if a PostGIS session is active (Pro)</li></ul></li><li>Metadata preview (CRS, feature count, format)</li></ul><h3 id="jobs-panel" tabindex="-1">Jobs Panel <a class="header-anchor" href="#jobs-panel" aria-label="Permalink to &quot;Jobs Panel&quot;">​</a></h3><ul><li>Create and execute jobs on a selected dataset</li><li>Real-time execution monitoring (progress bar)</li><li>Download the result as a new QGIS layer</li><li>Recent job history</li></ul><h3 id="triggers-panel-pro" tabindex="-1">Triggers Panel (Pro) <a class="header-anchor" href="#triggers-panel-pro" aria-label="Permalink to &quot;Triggers Panel (Pro)&quot;">​</a></h3><ul><li>View and manage active triggers on the server</li><li>Enable/disable a trigger</li><li>View recent events</li></ul><h3 id="scenarios-panel-pro" tabindex="-1">Scenarios Panel (Pro) <a class="header-anchor" href="#scenarios-panel-pro" aria-label="Permalink to &quot;Scenarios Panel (Pro)&quot;">​</a></h3><ul><li>Browse and execute defined scenarios</li><li>Monitor DAG execution</li></ul><h2 id="loading-data-from-gispulse" tabindex="-1">Loading Data from GISPulse <a class="header-anchor" href="#loading-data-from-gispulse" aria-label="Permalink to &quot;Loading Data from GISPulse&quot;">​</a></h2><h3 id="via-ogc-api-features" tabindex="-1">Via OGC API Features <a class="header-anchor" href="#via-ogc-api-features" aria-label="Permalink to &quot;Via OGC API Features&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Datasets Panel -&gt; select a dataset -&gt; Load (OGC)</span></span></code></pre></div><p>The layer is loaded in QGIS as a standard WFS vector layer. Supports bbox and attribute filters.</p><h3 id="via-mvt-vector-tiles" tabindex="-1">Via MVT (vector tiles) <a class="header-anchor" href="#via-mvt-vector-tiles" aria-label="Permalink to &quot;Via MVT (vector tiles)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Datasets Panel -&gt; select a dataset -&gt; Load (MVT)</span></span></code></pre></div><p>Ideal for datasets with &gt; 100,000 features. The layer is loaded as a MapLibre vector tile layer.</p><p>MVT endpoint URL:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:8001/ogc/collections/{dataset_id}/tiles/{z}/{x}/{y}.mvt</span></span></code></pre></div><h3 id="via-direct-postgis-pro" tabindex="-1">Via direct PostGIS (Pro) <a class="header-anchor" href="#via-direct-postgis-pro" aria-label="Permalink to &quot;Via direct PostGIS (Pro)&quot;">​</a></h3><p>When a PostGIS session is active, the plugin can load PostGIS tables directly via QGIS&#39;s PostgreSQL connection. Layers stay synchronized with the backend.</p><h2 id="running-a-job-from-qgis" tabindex="-1">Running a Job from QGIS <a class="header-anchor" href="#running-a-job-from-qgis" aria-label="Permalink to &quot;Running a Job from QGIS&quot;">​</a></h2><ol><li>Select a dataset in the Datasets panel</li><li>Go to the Jobs panel</li><li>Choose the rules to apply (or a scenario)</li><li>Click <strong>Run</strong></li><li>Monitor the progress</li><li>Once completed: <strong>Load Result</strong> to add the layer to QGIS</li></ol><h2 id="geoprocessing-tools" tabindex="-1">Geoprocessing Tools <a class="header-anchor" href="#geoprocessing-tools" aria-label="Permalink to &quot;Geoprocessing Tools&quot;">​</a></h2><p>The plugin exposes 3 tools in the <strong>QGIS Processing Toolbox</strong>:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>GISPulse — Run Rules</code></td><td>Execute rules on the active layer</td></tr><tr><td><code>GISPulse — Upload Dataset</code></td><td>Upload the active layer to GISPulse</td></tr><tr><td><code>GISPulse — Export Result</code></td><td>Download the result of a job</td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="connection-refused" tabindex="-1">&quot;Connection refused&quot; <a class="header-anchor" href="#connection-refused" aria-label="Permalink to &quot;&quot;Connection refused&quot;&quot;">​</a></h3><p>Make sure <code>gispulse portal</code> is running on the specified port.</p><h3 id="unauthorized" tabindex="-1">&quot;Unauthorized&quot; <a class="header-anchor" href="#unauthorized" aria-label="Permalink to &quot;&quot;Unauthorized&quot;&quot;">​</a></h3><p>Check the API key in the plugin settings (<strong>Plugins -&gt; GISPulse -&gt; Settings</strong>).</p><h3 id="empty-mvt-layers" tabindex="-1">Empty MVT layers <a class="header-anchor" href="#empty-mvt-layers" aria-label="Permalink to &quot;Empty MVT layers&quot;">​</a></h3><p>The MVT endpoint requires the dataset to be indexed on the server side. Try loading via OGC first.</p><h2 id="plugin-development" tabindex="-1">Plugin Development <a class="header-anchor" href="#plugin-development" aria-label="Permalink to &quot;Plugin Development&quot;">​</a></h2><p>See <a href="/gispulse/plugins/developing">Developing a Plugin</a> to contribute or create your own GISPulse plugin.</p><p>Source code: <code>clients/qgis/gispulse_qgis/</code></p>`,49)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
